 @page "/notepad"
 @rendermode InteractiveServer
 @inject IJSRuntime JS
 @implements IAsyncDisposable

 <PageTitle>Notepad</PageTitle>

 <h1>Notepad</h1>

 <textarea class="form-control mb-3" rows="12" @bind="content" @bind:event="oninput"
           @bind:after="OnContentChanged" placeholder="Type your notes here..." />

 <div class="d-flex align-items-center gap-2 mb-3">
     <button class="btn btn-primary" @onclick="SaveNowAsync">Save now</button>
     <button class="btn btn-danger" @onclick="ClearAsync">Clear</button>
     @if (lastSavedAt is not null)
     {
         <span class="text-muted">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
     }
 </div>

 @code {
     private string content = string.Empty;
     private DateTime? lastSavedAt;
     private NotepadInterop? interop;
     private DotNetObjectReference<Notepad>? dotNetRef;
     private Timer? autoSaveTimer;
     private bool isDirty;

     protected override async Task OnAfterRenderAsync(bool firstRender)
     {
         if (firstRender)
         {
             interop = new NotepadInterop(JS);
             dotNetRef = DotNetObjectReference.Create(this);

             var saved = await interop.InitializeAsync(dotNetRef);
             if (!string.IsNullOrEmpty(saved))
             {
                 content = saved;
                 StateHasChanged();
             }

             autoSaveTimer = new Timer(AutoSaveCallback, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
         }
     }

     private async Task OnContentChanged()
     {
         if (interop is not null && !isDirty)
         {
             await interop.MarkDirtyAsync();
         }
     }

     private async Task SaveNowAsync()
     {
         if (interop is not null)
         {
             await interop.SaveAsync(content);
             lastSavedAt = DateTime.Now;
         }
     }

     private async Task ClearAsync()
     {
         if (interop is not null)
         {
             content = string.Empty;
             await interop.ClearAsync();
             lastSavedAt = null;
         }
     }

     private async void AutoSaveCallback(object? state)
     {
         if (interop is not null && isDirty)
         {
             await InvokeAsync(async () =>
             {
                 await interop.SaveAsync(content);
                 lastSavedAt = DateTime.Now;
                 StateHasChanged();
             });
         }
     }

     [JSInvokable]
     public async Task OnDirtyChanged(bool dirty)
     {
         await InvokeAsync(() =>
         {
             isDirty = dirty;
         });
     }

     public async ValueTask DisposeAsync()
     {
         if (autoSaveTimer is not null)
         {
             await autoSaveTimer.DisposeAsync();
         }

         if (interop is not null)
         {
             await interop.DisposeAsync();
         }

         dotNetRef?.Dispose();
     }
 }
